"use client";

import { useRef, useEffect, useState, useCallback } from 'react';
import { initPointerLayout, stepPointerLayout, isAtRest } from '../core/pointer.js';
import { createCanvasMeasure } from '../renderers/svg.js';
import { mountSemantic } from '../a11y/semantic.js';
import type { SemanticTag } from '../a11y/semantic.js';
import type { PointerMode, PointerLayoutState } from '../core/types.js';

export interface PointerTextProps {
  children: string;
  font: string;
  mode: PointerMode;
  as?: SemanticTag;
  spacing?: number;
  radius?: number;
  strength?: number;
  fill?: string;
  /** Props forwarded to the visual <svg> element. */
  svgProps?: Omit<React.SVGAttributes<SVGSVGElement>, 'children' | 'viewBox'>;
}

const SVG_NS = 'http://www.w3.org/2000/svg';

function settledState(state: PointerLayoutState): PointerLayoutState {
  return {
    ...state,
    pointer: null,
    glyphs: state.glyphs.map((glyph) => ({
      ...glyph,
      position: { ...glyph.base },
      velocity: { x: 0, y: 0 },
      angle: 0,
    })),
  };
}

export function PointerText({
  children,
  font,
  mode,
  as = 'span',
  spacing = 1.05,
  radius = 120,
  strength = 0.6,
  fill = 'currentColor',
  svgProps,
}: PointerTextProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const stateRef = useRef<ReturnType<typeof initPointerLayout> | null>(null);
  const animatingRef = useRef(false);
  const frameRef = useRef<number | null>(null);
  const interactiveRef = useRef(false);
  const textNodesRef = useRef<(SVGTextElement | null)[]>([]);
  const semanticRef = useRef<ReturnType<typeof mountSemantic> | null>(null);
  const viewBoxRef = useRef({ width: 1, height: 1 });
  const [viewBox, setViewBox] = useState('0 0 1 1');

  const updateNodes = useCallback(() => {
    const state = stateRef.current;
    if (!state) return;
    const nodes = textNodesRef.current;
    for (let i = 0; i < state.glyphs.length; i++) {
      const node = nodes[i];
      if (!node) continue;
      const glyph = state.glyphs[i]!;
      node.setAttribute(
        'transform',
        `translate(${glyph.position.x}, ${glyph.position.y}) rotate(${(glyph.angle * 180) / Math.PI})`,
      );
    }
  }, []);

  const stopLoop = useCallback(() => {
    animatingRef.current = false;
    if (frameRef.current !== null) {
      cancelAnimationFrame(frameRef.current);
      frameRef.current = null;
    }
  }, []);

  const settle = useCallback(() => {
    stopLoop();
    if (stateRef.current) {
      stateRef.current = settledState(stateRef.current);
      updateNodes();
    }
  }, [stopLoop, updateNodes]);

  const startLoop = useCallback(() => {
    if (animatingRef.current || !interactiveRef.current) return;
    animatingRef.current = true;
    let lastTime = performance.now();

    function tick(now: number) {
      frameRef.current = null;
      if (!animatingRef.current || !interactiveRef.current) {
        animatingRef.current = false;
        return;
      }

      const state = stateRef.current;
      if (!state) {
        animatingRef.current = false;
        return;
      }

      const dt = Math.min((now - lastTime) / 1000, 0.05);
      lastTime = now;
      const next = stepPointerLayout(state, state.pointer, radius, strength, dt);
      stateRef.current = next;
      updateNodes();

      if (!next.pointer && isAtRest(next)) {
        animatingRef.current = false;
        return;
      }
      frameRef.current = requestAnimationFrame(tick);
    }

    frameRef.current = requestAnimationFrame(tick);
  }, [radius, strength, updateNodes]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    semanticRef.current = mountSemantic(container, children, as);
    return () => {
      semanticRef.current?.destroy();
      semanticRef.current = null;
    };
  }, [as]);

  useEffect(() => {
    semanticRef.current?.update(children);
  }, [children]);

  useEffect(() => {
    const svg = svgRef.current;
    if (!svg) return;
    const svgElement = svg;

    let disposed = false;
    let group: SVGGElement | null = null;
    stopLoop();

    function setup() {
      if (disposed) return;
      const measure = createCanvasMeasure(font);
      const state = initPointerLayout(children, measure, mode, spacing);
      const fontHeight = state.glyphs.reduce(
        (height, glyph) => Math.max(height, glyph.metrics.height),
        parseFloat(font) || 16,
      );
      const lastGlyph = state.glyphs[state.glyphs.length - 1];
      const textWidth = lastGlyph
        ? lastGlyph.position.x + lastGlyph.metrics.width / 2
        : fontHeight;
      const padding = Math.max(radius / 2, fontHeight);
      const width = Math.max(textWidth + padding * 2, 1);
      const height = Math.max(fontHeight + padding * 2, 1);

      for (const glyph of state.glyphs) {
        glyph.base = { x: glyph.base.x + padding, y: height / 2 };
        glyph.position = { ...glyph.base };
      }

      stateRef.current = state;
      viewBoxRef.current = { width, height };
      setViewBox(`0 0 ${width} ${height}`);

      group = document.createElementNS(SVG_NS, 'g');
      group.setAttribute('aria-hidden', 'true');
      svgElement.appendChild(group);

      const nodes: (SVGTextElement | null)[] = [];
      for (const glyph of state.glyphs) {
        if (glyph.char.trim() === '') {
          nodes.push(null);
          continue;
        }
        const text = document.createElementNS(SVG_NS, 'text') as SVGTextElement;
        text.setAttribute('fill', fill);
        text.setAttribute('text-anchor', 'middle');
        text.setAttribute('dominant-baseline', 'central');
        text.style.font = font;
        text.textContent = glyph.char;
        text.setAttribute('transform', `translate(${glyph.position.x}, ${glyph.position.y})`);
        group.appendChild(text);
        nodes.push(text);
      }
      textNodesRef.current = nodes;
    }

    const fontReady = document.fonts?.load(font, children || ' ') ?? Promise.resolve([]);
    void fontReady.then(setup, setup);

    return () => {
      disposed = true;
      stopLoop();
      group?.remove();
      stateRef.current = null;
      textNodesRef.current = [];
    };
  }, [children, fill, font, mode, radius, spacing, stopLoop]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)');
    const coarsePointer = window.matchMedia('(hover: none), (pointer: coarse)');
    let onscreen = true;

    const updateInteraction = () => {
      interactiveRef.current =
        !document.hidden && onscreen && !reducedMotion.matches && !coarsePointer.matches;
      if (!interactiveRef.current) settle();
    };
    const observer =
      typeof IntersectionObserver === 'undefined'
        ? null
        : new IntersectionObserver(([entry]) => {
            onscreen = entry?.isIntersecting ?? false;
            updateInteraction();
          });

    reducedMotion.addEventListener('change', updateInteraction);
    coarsePointer.addEventListener('change', updateInteraction);
    document.addEventListener('visibilitychange', updateInteraction);
    observer?.observe(container);
    updateInteraction();

    return () => {
      reducedMotion.removeEventListener('change', updateInteraction);
      coarsePointer.removeEventListener('change', updateInteraction);
      document.removeEventListener('visibilitychange', updateInteraction);
      observer?.disconnect();
      interactiveRef.current = false;
      settle();
    };
  }, [settle]);

  const onPointerMove = useCallback(
    (event: React.PointerEvent<SVGSVGElement>) => {
      svgProps?.onPointerMove?.(event);
      if (event.pointerType === 'touch') {
        settle();
        return;
      }

      const svg = svgRef.current;
      const state = stateRef.current;
      if (!svg || !state || !interactiveRef.current) return;
      const rect = svg.getBoundingClientRect();
      if (!rect.width || !rect.height) return;
      const { width, height } = viewBoxRef.current;
      stateRef.current = {
        ...state,
        pointer: {
          x: (event.clientX - rect.left) * (width / rect.width),
          y: (event.clientY - rect.top) * (height / rect.height),
        },
      };
      startLoop();
    },
    [settle, startLoop, svgProps],
  );

  const onPointerEnd = useCallback(
    (event: React.PointerEvent<SVGSVGElement>) => {
      if (event.type === 'pointercancel') svgProps?.onPointerCancel?.(event);
      else svgProps?.onPointerLeave?.(event);
      const state = stateRef.current;
      if (state) stateRef.current = { ...state, pointer: null };
      startLoop();
    },
    [startLoop, svgProps],
  );

  return (
    <div ref={containerRef} style={{ position: 'relative' }}>
      <svg
        {...svgProps}
        ref={svgRef}
        viewBox={viewBox}
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
        focusable="false"
        tabIndex={-1}
        preserveAspectRatio="xMidYMid meet"
        onPointerMove={onPointerMove}
        onPointerLeave={onPointerEnd}
        onPointerCancel={onPointerEnd}
        style={{ display: 'block', width: '100%', height: 'auto', ...svgProps?.style }}
      />
    </div>
  );
}

import type {
  Point,
  MeasureFn,
  PointerMode,
  PointerGlyphState,
  PointerLayoutState,
} from './types.js';

// ---- Spring physics constants ----

// Low stiffness + high damping retention = slow, fluid return with inertia
const SPRING_STIFFNESS = 0.03;
const DAMPING = 0.92;
// Below this velocity magnitude, snap to rest
const REST_THRESHOLD = 0.05;

// ---- Initialization ----

/**
 * Create the initial state for a pointer-reactive layout.
 * Characters are laid out in a horizontal line starting from (0, 0).
 * Pure function — no DOM.
 */
export function initPointerLayout(
  text: string,
  measure: MeasureFn,
  mode: PointerMode,
  spacing = 1,
): PointerLayoutState {
  const chars = [...text];
  const glyphs: PointerGlyphState[] = [];
  let cursor = 0;

  for (let i = 0; i < chars.length; i++) {
    const char = chars[i]!;
    const metrics = measure(char, i);
    const advance = metrics.width * spacing;
    const x = cursor + advance / 2;
    const base: Point = { x, y: 0 };

    glyphs.push({
      char,
      index: i,
      base,
      position: { ...base },
      angle: 0,
      velocity: { x: 0, y: 0 },
      metrics,
    });

    cursor += advance;
  }

  return { glyphs, text, pointer: null, mode };
}

// ---- Per-frame update ----

/**
 * Compute the next frame of the pointer-reactive layout.
 * Returns a new state — does not mutate the input.
 *
 * @param state - Current layout state
 * @param pointer - Current pointer position (null if pointer left the area)
 * @param radius - Effect radius in pixels
 * @param strength - Effect strength, 0–1
 * @param dt - Time delta in seconds (for frame-rate independence). Default ~16ms.
 */
export function stepPointerLayout(
  state: PointerLayoutState,
  pointer: Point | null,
  radius: number,
  strength: number,
  dt = 1 / 60,
): PointerLayoutState {
  // Normalize dt to 60fps baseline so spring constants feel consistent
  const dtScale = dt * 60;

  const glyphs = state.glyphs.map((glyph): PointerGlyphState => {
    let forceX = 0;
    let forceY = 0;

    if (pointer) {
      // Use base position for force calculation — keeps the force field
      // stable regardless of where the glyph has been displaced to.
      // Otherwise glyphs that move away lose influence and snap back.
      const dx = glyph.base.x - pointer.x;
      const dy = glyph.base.y - pointer.y;
      const distSq = dx * dx + dy * dy;
      const dist = Math.sqrt(distSq);

      if (dist < radius && dist > 0.001) {
        // Normalized distance: 1 at pointer, 0 at edge of radius
        const proximity = 1 - dist / radius;
        // Smooth falloff
        const influence = proximity * proximity * strength;

        switch (state.mode) {
          case 'repel': {
            // Push away from pointer along the displacement vector
            const normX = dx / dist;
            const normY = dy / dist;
            forceX = normX * influence * radius * 0.3;
            forceY = normY * influence * radius * 0.3;
            break;
          }
          case 'attract': {
            // Pull toward pointer
            const normX = dx / dist;
            const normY = dy / dist;
            forceX = -normX * influence * radius * 0.15;
            forceY = -normY * influence * radius * 0.15;
            break;
          }
          case 'orbit': {
            // Perpendicular to displacement vector (tangential force)
            const normX = dx / dist;
            const normY = dy / dist;
            // Tangent: rotate 90 degrees
            forceX = -normY * influence * radius * 0.2;
            forceY = normX * influence * radius * 0.2;
            // Plus a slight inward pull to keep orbiting
            forceX -= normX * influence * radius * 0.05;
            forceY -= normY * influence * radius * 0.05;
            break;
          }
        }
      }
    }

    // Target = base position + force displacement
    const targetX = glyph.base.x + forceX;
    const targetY = glyph.base.y + forceY;

    // Spring: accelerate toward target
    const ax = (targetX - glyph.position.x) * SPRING_STIFFNESS;
    const ay = (targetY - glyph.position.y) * SPRING_STIFFNESS;

    let vx = (glyph.velocity.x + ax * dtScale) * DAMPING;
    let vy = (glyph.velocity.y + ay * dtScale) * DAMPING;

    // Snap to rest if close enough
    const speed = Math.sqrt(vx * vx + vy * vy);
    const distToTarget = Math.sqrt(
      (glyph.position.x - targetX) ** 2 + (glyph.position.y - targetY) ** 2,
    );
    if (speed < REST_THRESHOLD && distToTarget < REST_THRESHOLD) {
      vx = 0;
      vy = 0;
    }

    const newX = glyph.position.x + vx * dtScale;
    const newY = glyph.position.y + vy * dtScale;

    // Rotation: blend toward direction of movement, ease back to 0
    const targetAngle = speed > 0.5 ? Math.atan2(vy, vx) : 0;
    const angle = glyph.angle + (targetAngle - glyph.angle) * 0.1;

    return {
      ...glyph,
      position: { x: newX, y: newY },
      velocity: { x: vx, y: vy },
      angle,
    };
  });

  return { ...state, glyphs, pointer };
}

/**
 * Check if the layout is at rest (all characters settled).
 * Useful to stop the animation loop when nothing is moving.
 */
export function isAtRest(state: PointerLayoutState): boolean {
  return state.glyphs.every((g) => {
    const speed = Math.sqrt(g.velocity.x ** 2 + g.velocity.y ** 2);
    const distToBase = Math.sqrt(
      (g.position.x - g.base.x) ** 2 + (g.position.y - g.base.y) ** 2,
    );
    return speed < REST_THRESHOLD && distToBase < REST_THRESHOLD;
  });
}

// ---- Geometry primitives ----

export interface Point {
  x: number;
  y: number;
}

// ---- Bezier path representation ----

/** A moveto command — starts a new subpath */
export interface MoveToSegment {
  type: 'M';
  to: Point;
}

/** A cubic bezier: two control points + endpoint */
export interface CubicSegment {
  type: 'C';
  cp1: Point;
  cp2: Point;
  to: Point;
}

/** A quadratic bezier: one control point + endpoint */
export interface QuadraticSegment {
  type: 'Q';
  cp: Point;
  to: Point;
}

/** A straight line segment */
export interface LineSegment {
  type: 'L';
  to: Point;
}

export type PathSegment = MoveToSegment | CubicSegment | QuadraticSegment | LineSegment;

/** A parsed path — just the segments, no string form */
export interface ParsedPath {
  segments: PathSegment[];
}

// ---- Font / character measurement ----

/**
 * Character metrics provided by the caller. The layout engine is pure —
 * it doesn't measure text itself. The caller (or a renderer-side helper)
 * supplies these measurements.
 */
export interface CharMetrics {
  /** Advance width of the character */
  width: number;
  /** Height of the character (ascent + descent) */
  height: number;
}

/**
 * A function that returns metrics for a character at a given index.
 * This is how the layout engine stays pure — measurement is injected.
 */
export type MeasureFn = (char: string, index: number) => CharMetrics;

// ---- Layout output ----

/** A single character positioned in 2D space */
export interface GlyphLayout {
  /** The character */
  char: string;
  /** Index in the original string */
  index: number;
  /** Position on the path (center of the character baseline) */
  position: Point;
  /** Rotation in radians, following the path tangent */
  angle: number;
  /** The metrics used for this character */
  metrics: CharMetrics;
}

/** Full result of a path layout computation */
export interface PathLayoutResult {
  /** Per-character layout data */
  glyphs: GlyphLayout[];
  /** The original text */
  text: string;
  /** Total arc length consumed by the text */
  textLength: number;
  /** Total arc length of the path */
  pathLength: number;
}

// ---- Path layout options ----

export interface PathLayoutOptions {
  /** SVG path data string (e.g. "M 0 0 C 100 0 200 100 300 100") */
  path: string;
  /**
   * Font shorthand, e.g. "16px Inter".
   * Used by renderers to derive a MeasureFn — the core engine
   * accepts a MeasureFn directly when you call computePathLayout.
   */
  font: string;
  /** Letter-spacing multiplier. 1 = normal, 1.2 = 20% wider. Default 1. */
  spacing?: number;
  /** Offset along the path to start placing text. Default 0. */
  startOffset?: number;
  /** How to align text when it's shorter than the path */
  align?: 'start' | 'center' | 'end';
}

// ---- Pointer-reactive layout ----

export type PointerMode = 'repel' | 'attract' | 'orbit';

export interface PointerLayoutOptions {
  font: string;
  mode: PointerMode;
  /** Effect radius in pixels. Default 100. */
  radius?: number;
  /** Strength of the effect, 0–1. Default 0.5. */
  strength?: number;
}

/** A single character in the pointer-reactive layout */
export interface PointerGlyphState {
  char: string;
  index: number;
  /** Base position (where it sits with no pointer influence) */
  base: Point;
  /** Current displaced position */
  position: Point;
  /** Current rotation in radians */
  angle: number;
  /** Velocity for spring physics */
  velocity: Point;
  metrics: CharMetrics;
}

/** Snapshot of the full pointer-reactive layout state */
export interface PointerLayoutState {
  glyphs: PointerGlyphState[];
  text: string;
  pointer: Point | null;
  mode: PointerMode;
}

import type { PathLayoutResult, MeasureFn, CharMetrics } from '../core/types.js';

// ---- Text measurement via offscreen canvas ----

/**
 * Create a MeasureFn from a CSS font string using an offscreen canvas.
 * This is the bridge between the pure layout engine and the DOM.
 */
export function createCanvasMeasure(font: string): MeasureFn {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d')!;
  ctx.font = font;

  // Cache measurements — same character always has the same metrics
  const cache = new Map<string, CharMetrics>();

  return (char: string, _index: number): CharMetrics => {
    const cached = cache.get(char);
    if (cached) return cached;

    const tm = ctx.measureText(char);
    const metrics: CharMetrics = {
      width: tm.width,
      height: (tm.actualBoundingBoxAscent ?? 0) + (tm.actualBoundingBoxDescent ?? 0) || parseFloat(font) || 16,
    };
    cache.set(char, metrics);
    return metrics;
  };
}

// ---- SVG namespace ----

const SVG_NS = 'http://www.w3.org/2000/svg';

function svgEl<K extends keyof SVGElementTagNameMap>(tag: K): SVGElementTagNameMap[K] {
  return document.createElementNS(SVG_NS, tag);
}

// ---- SVG renderer ----

export interface SvgRenderOptions {
  /** CSS font string applied to the <text> elements */
  font: string;
  /** Fill color. Default "currentColor". */
  fill?: string;
  /** Whether to include the raw path as a visible <path> element (debug). Default false. */
  debugPath?: boolean;
  /** SVG path data string — only needed if debugPath is true */
  pathData?: string;
}

/**
 * Render a PathLayoutResult into an SVG group element (<g>).
 * Returns the <g> — caller appends it wherever they want.
 */
export function renderSvgGroup(layout: PathLayoutResult, options: SvgRenderOptions): SVGGElement {
  const g = svgEl('g');
  g.setAttribute('aria-hidden', 'true');

  if (options.debugPath && options.pathData) {
    const path = svgEl('path');
    path.setAttribute('d', options.pathData);
    path.setAttribute('fill', 'none');
    path.setAttribute('stroke', 'rgba(255,255,255,0.15)');
    path.setAttribute('stroke-width', '1');
    g.appendChild(path);
  }

  const fill = options.fill ?? 'currentColor';

  for (const glyph of layout.glyphs) {
    // Skip whitespace — no visible glyph needed
    if (glyph.char.trim() === '') continue;

    const text = svgEl('text');
    text.setAttribute('font', options.font);
    text.setAttribute('fill', fill);
    text.setAttribute('text-anchor', 'middle');
    text.setAttribute('dominant-baseline', 'central');
    text.setAttribute(
      'transform',
      `translate(${glyph.position.x}, ${glyph.position.y}) rotate(${(glyph.angle * 180) / Math.PI})`,
    );
    text.textContent = glyph.char;
    g.appendChild(text);
  }

  return g;
}

/**
 * Render into an existing SVG element, clearing previous content.
 */
export function renderToSvg(svg: SVGSVGElement, layout: PathLayoutResult, options: SvgRenderOptions): void {
  // Remove previous drifttype output
  const existing = svg.querySelector('[data-drifttype]');
  if (existing) existing.remove();

  const g = renderSvgGroup(layout, options);
  g.setAttribute('data-drifttype', '');
  svg.appendChild(g);
}

/**
 * Update an existing rendered group in-place.
 * More efficient than re-rendering — reuses DOM nodes when possible.
 */
export function updateSvgGroup(g: SVGGElement, layout: PathLayoutResult, options: SvgRenderOptions): void {
  const textNodes = g.querySelectorAll('text');
  const visibleGlyphs = layout.glyphs.filter((gl) => gl.char.trim() !== '');

  // If glyph count changed, just re-render
  if (textNodes.length !== visibleGlyphs.length) {
    g.innerHTML = '';
    const fresh = renderSvgGroup(layout, options);
    while (fresh.firstChild) {
      g.appendChild(fresh.firstChild);
    }
    return;
  }

  // Update transforms in place
  for (let i = 0; i < visibleGlyphs.length; i++) {
    const glyph = visibleGlyphs[i]!;
    const node = textNodes[i]!;
    node.setAttribute(
      'transform',
      `translate(${glyph.position.x}, ${glyph.position.y}) rotate(${(glyph.angle * 180) / Math.PI})`,
    );
    if (node.textContent !== glyph.char) {
      node.textContent = glyph.char;
    }
  }
}

/**
 * Semantic layer — keeps a hidden, accessible text node in sync
 * with the visual output so screen readers see real text.
 *
 * The visual element gets aria-hidden="true".
 * The semantic element is visually hidden but available to assistive tech.
 */

export type SemanticTag = 'span' | 'p' | 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';

export interface SemanticHandle {
  /** Update the accessible text content */
  update(text: string): void;
  /** Remove the semantic node from the DOM */
  destroy(): void;
  /** The hidden element, in case the caller needs a reference */
  element: HTMLElement;
}

// Visually hidden but accessible — standard sr-only technique
const SR_STYLES: Partial<CSSStyleDeclaration> = {
  position: 'absolute',
  width: '1px',
  height: '1px',
  padding: '0',
  margin: '-1px',
  overflow: 'hidden',
  // clip-path is the modern replacement for clip: rect(0,0,0,0)
  clipPath: 'inset(50%)',
  whiteSpace: 'nowrap',
  border: '0',
};

/**
 * Mount a semantic text layer into a container.
 * Returns a handle to update or destroy it.
 */
export function mountSemantic(
  container: HTMLElement,
  text: string,
  tagName: SemanticTag = 'span',
): SemanticHandle {
  const el = document.createElement(tagName);
  Object.assign(el.style, SR_STYLES);
  el.textContent = text;

  container.appendChild(el);

  return {
    update(newText: string) {
      el.textContent = newText;
    },
    destroy() {
      el.remove();
    },
    element: el,
  };
}
